      return 'https://stacks-node-api.mainnet.stacks.co'
    case 'testnet':
      return 'https://stacks-node-api.testnet.stacks.co'
    case 'devnet':
      return 'http://localhost:20443'
    default:
      return 'https://stacks-node-api.testnet.stacks.co'
