/**
 * Actions Plugin for @secondlayer/cli
 * Generates read and write helper functions for direct blockchain interaction
 */

import { generateActionHelpers } from "./generators";
import type {
  PluginFactory,
  // UserConfig,
  GenerateContext,
} from "../../types/plugin";

export interface ActionsPluginOptions {
  /** Include only specific contracts */
  include?: string[];

  /** Exclude specific contracts */
  exclude?: string[];

  /** Include only specific functions */
  includeFunctions?: string[];

  /** Exclude specific functions */
  excludeFunctions?: string[];

  /** Enable debug output */
  debug?: boolean;

  /** Environment variable name for default sender key (default: "STX_SENDER_KEY") */
  senderKeyEnv?: string;
}

/**
 * Actions plugin factory
 */
export const actions: PluginFactory<ActionsPluginOptions> = (options = {}) => {
  return {
    name: "@secondlayer/cli/plugin-actions",
    version: "1.0.0",

    async generate(context: GenerateContext): Promise<void> {
      const { contracts } = context;

      // Filter contracts based on options
      const filteredContracts = contracts.filter((contract) => {
        if (options.include && !options.include.includes(contract.name)) {
          return false;
        }
        if (options.exclude && options.exclude.includes(contract.name)) {
          return false;
        }
        return true;
      });

      if (filteredContracts.length === 0) {
        if (options.debug) {
          context.logger.debug("Actions plugin: No contracts to process");
        }
        return;
      }

      if (options.debug) {
        context.logger.debug(
          `Actions plugin: Generating read/write helpers for ${filteredContracts.length} contracts`
        );
      }

      // Collect all helpers for all contracts
      const contractHelpers = new Map<string, string>();

      for (const contract of filteredContracts) {
        const actionsCode = await generateActionHelpers(contract, options);
        if (actionsCode) {
          contractHelpers.set(contract.name, actionsCode);
        }
      }

      // Inject all helpers into the output
      if (contractHelpers.size > 0) {
        const existingOutput = context.outputs.get("contracts");
        if (existingOutput) {
          let modifiedContent = addRequiredImports(existingOutput.content);

          // Inject helpers for each contract
          for (const [contractName, helpersCode] of contractHelpers) {
            modifiedContent = injectHelpersIntoContract(
              modifiedContent,
              contractName,
              helpersCode
            );
          }

          context.outputs.set("contracts", {
            ...existingOutput,
            content: modifiedContent,
          });
        }
      }
    },
  };
};

/**
 * Add required imports for fetchCallReadOnlyFunction, makeContractCall, and PostCondition
 */
function addRequiredImports(content: string): string {
  // Find the existing @secondlayer/stacks import line
  const stacksImportRegex =
    /import\s+\{([^}]+)\}\s+from\s+['"]@secondlayer\/stacks['"];/;
  const match = content.match(stacksImportRegex);

  if (match) {
    let updatedContent = content;

    // Add fetchCallReadOnlyFunction and makeContractCall from @secondlayer/stacks/clarity
    if (!updatedContent.includes("fetchCallReadOnlyFunction")) {
      updatedContent = updatedContent.replace(
        stacksImportRegex,
        `${match[0]}\nimport { fetchCallReadOnlyFunction, makeContractCall } from '@secondlayer/stacks/clarity';`
      );
    }

    // Add type import for PostCondition if not present
    if (!updatedContent.includes("type PostCondition")) {
      updatedContent = updatedContent.replace(
        stacksImportRegex,
        `${match[0]}\nimport type { PostCondition } from '@secondlayer/stacks';`
      );
    }

    return updatedContent;
  }

  return content;
}

/**
 * Inject read/write helpers into a specific contract object in the output
 */
function injectHelpersIntoContract(
  content: string,
  contractName: string,
  helpersCode: string
): string {
  // Use a more precise regex to find the entire contract object
  const contractPattern = new RegExp(
    `(export const ${contractName} = \\{[\\s\\S]*?)\\n\\} as const;`,
    "g"
  );

  return content.replace(contractPattern, (_, contractBody) => {
    // Remove any trailing comma and whitespace from the contract body
    const cleanBody = contractBody.replace(/,\s*$/, "");

    // Add proper indentation to lines that start top-level properties
    const indentedHelpersCode = helpersCode
      .split("\n")
      .map((line) => {
        // Only add indentation to lines that start with a property name (like "write:")
        if (line.match(/^[a-zA-Z_$][a-zA-Z0-9_$]*\s*:/)) {
          return `  ${line}`;
        }
        return line;
      })
      .join("\n");

    // Add the helpers with proper formatting
    return `${cleanBody},

${indentedHelpersCode}
} as const;`;
  });
}

/**
 * Clarinet Plugin for @secondlayer/cli
 * Generates type-safe contract interfaces from local Clarity contracts using Clarinet SDK
 */

import { initSimnet } from "@hirosystems/clarinet-sdk";
import { toCamelCase } from "@secondlayer/stacks/clarity";
import { parseContractId } from "../../utils/contract-id";
import { generateContractInterface } from "../../generators/contract";
import { normalizeAbi } from "../../utils/abi-compat";
import type {
  PluginFactory,
  UserConfig,
  GenerateContext,
} from "../../types/plugin";

export interface ClarinetPluginOptions {
  /** Path to Clarinet.toml file */
  path?: string;

  /** Include only specific contracts */
  include?: string[];

  /** Exclude specific contracts */
  exclude?: string[];

  /** Enable debug output */
  debug?: boolean;
}

/**
 * Sanitize contract name to be a valid JavaScript identifier using camelCase
 */
function sanitizeContractName(name: string): string {
  return toCamelCase(name);
}

/**
 * Check if a contract is a user-defined contract (not a system contract)
 */
async function isUserDefinedContract(
  contractId: string,
  manifestPath: string
): Promise<boolean> {
  const { address, contractName } = parseContractId(contractId);

  try {
    // Read Clarinet.toml to get user-defined contracts
    const { promises: fs } = await import("fs");
    const tomlContent = await fs.readFile(manifestPath, "utf-8");

    // Simple TOML parsing to find [contracts.CONTRACT_NAME] sections
    const contractSectionRegex = /^\[contracts\.([^\]]+)\]/gm;
    const userContracts = new Set<string>();

    let match;
    while ((match = contractSectionRegex.exec(tomlContent)) !== null) {
      userContracts.add(match[1]);
    }

    // If the contract is explicitly defined in Clarinet.toml, it's user-defined
    if (userContracts.has(contractName)) {
      return true;
    }
  } catch (error) {
    // If we can't read the TOML file, fall back to pattern matching
  }

  // Fallback: System contracts typically have specific addresses or are in the boot contracts
  // Common system contract patterns:
  const systemContractPatterns = [
    /^pox-\d+$/, // pox-2, pox-3, etc.
    /^bns$/, // Blockchain Name System
    /^costs-\d+$/, // costs-2, costs-3, etc.
    /^lockup$/, // lockup contract
  ];

  // Check if it matches any system contract pattern
  if (systemContractPatterns.some((pattern) => pattern.test(contractName))) {
    return false;
  }

  // System contracts often use specific addresses
  const systemAddresses = [
    "SP000000000000000000002Q6VF78", // Boot contracts address
    "ST000000000000000000002AMW42H", // Boot contracts address (testnet)
  ];

  if (systemAddresses.includes(address)) {
    return false;
  }

  return true;
}

/**
 * Clarinet plugin factory
 */
export const clarinet: PluginFactory<ClarinetPluginOptions> = (
  options = {}
) => {
  const manifestPath = options.path || "./Clarinet.toml";
  let simnet: any;

  return {
    name: "@secondlayer/cli/plugin-clarinet",
    version: "1.0.0",

    async transformConfig(config: UserConfig): Promise<UserConfig> {
      try {
        // Initialize simnet to extract contract ABIs
        simnet = await initSimnet(manifestPath);

        // Get contract interfaces from Clarinet
        const contractInterfaces = simnet.getContractsInterfaces();
        const contracts = [];

        for (const [contractId, abi] of contractInterfaces) {
          const { contractName } = parseContractId(contractId);

          // Skip system contracts
          if (!(await isUserDefinedContract(contractId, manifestPath))) {
            if (options.debug) {
              console.log(`🚫 Skipping system contract: ${contractId}`);
            }
            continue;
          }

          // Apply user filters
          if (options.include && !options.include.includes(contractName)) {
            continue;
          }
          if (options.exclude && options.exclude.includes(contractName)) {
            continue;
          }

          // Sanitize the contract name for JavaScript export
          const sanitizedName = sanitizeContractName(contractName);

          // Don't set source field to avoid conflict with file resolution
          // Instead, we'll track this in metadata during processing
          contracts.push({
            name: sanitizedName,
            address: contractId,
            abi: normalizeAbi(abi),
            // Remove source field - this was causing the path resolution issue
            _clarinetSource: true, // Internal flag for our plugin
          });
        }

        if (options.debug) {
          console.log(
            `🔍 Clarinet plugin found ${contracts.length} user-defined contracts`
          );
        }

        return {
          ...config,
          contracts: [...(config.contracts || []), ...contracts],
        };
      } catch (error) {
        const err = error as Error;
        if (options.debug) {
          console.warn(
            `⚠️  Clarinet plugin failed to load contracts: ${err.message}`
          );
        }
        // If Clarinet.toml doesn't exist or fails, just return config unchanged
        return config;
      }
    },

    async generate(context: GenerateContext): Promise<void> {
      // Filter contracts that came from Clarinet
      const clarinetContracts = context.contracts.filter(
        (contract) => contract.metadata?.source === "clarinet"
      );

      if (clarinetContracts.length === 0) {
        return;
      }

      if (options.debug) {
        context.logger.debug(
          `Generating interfaces for ${clarinetContracts.length} Clarinet contracts`
        );
      }

      // Generate the main contracts file using existing generator
      const contractsCode = await generateContractInterface(clarinetContracts);

      context.addOutput("contracts", {
        path: context.config.out,
        content: contractsCode,
        type: "contracts",
      });

      // Don't log success here - let the main command handle it
    },
  };
};

/**
 * Utility function to check if a Clarinet project exists
 */
export async function hasClarinetProject(
  path = "./Clarinet.toml"
): Promise<boolean> {
  try {
    const { promises: fs } = await import("fs");
    await fs.access(path);
    return true;
  } catch {
    return false;
  }
}

