    const block = await db
      .selectFrom("blocks")
      .selectAll()
      .where("height", "=", 142800)
      .executeTakeFirst();

    expect(block).toBeDefined();
    expect(block!.hash).toBe(fixture.block_hash);
    expect(block!.canonical).toBe(true);
