import { describe, test, expect, beforeAll, afterAll } from "bun:test";
import { getDb } from "../index.ts";
import { sql } from "kysely";
import { findGaps, countMissingBlocks, computeContiguousTip } from "./integrity.ts";

const HAS_DB = !!process.env.DATABASE_URL;

describe.skipIf(!HAS_DB)("integrity queries", () => {
  const db = HAS_DB ? getDb() : (null as any);

  beforeAll(async () => {
    await sql`DELETE FROM events`.execute(db);
    await sql`DELETE FROM transactions`.execute(db);
    await sql`DELETE FROM blocks`.execute(db);
  });

  afterAll(async () => {
    await sql`DELETE FROM events`.execute(db);
    await sql`DELETE FROM transactions`.execute(db);
    await sql`DELETE FROM blocks`.execute(db);
  });

  async function insertBlock(height: number) {
    await db.insertInto("blocks").values({
      height,
      hash: `0x${height.toString(16).padStart(64, "0")}`,
      parent_hash: `0x${(height - 1).toString(16).padStart(64, "0")}`,
      burn_block_height: height,
      timestamp: Math.floor(Date.now() / 1000),
      canonical: true,
    }).onConflict((oc: any) => oc.column("height").doNothing()).execute();
  }

  test("findGaps detects gaps in block heights", async () => {
    // Insert blocks 1,2,3,7,8,12
    for (const h of [1, 2, 3, 7, 8, 12]) {
      await insertBlock(h);
    }

    const gaps = await findGaps(db);
    expect(gaps).toEqual([
      { gapStart: 4, gapEnd: 6, size: 3 },
      { gapStart: 9, gapEnd: 11, size: 3 },
    ]);
  });

  test("findGaps respects limit", async () => {
    const gaps = await findGaps(db, 1);
    expect(gaps).toHaveLength(1);
    expect(gaps[0]!.gapStart).toBe(4);
  });

  test("countMissingBlocks sums gap sizes", async () => {
    const count = await countMissingBlocks(db);
    expect(count).toBe(6);
  });

  test("computeContiguousTip finds contiguous range", async () => {
    // blocks: 1,2,3,7,8,12
    const tip = await computeContiguousTip(db, 1);
    expect(tip).toBe(3);
  });

  test("computeContiguousTip from middle of contiguous range", async () => {
    const tip = await computeContiguousTip(db, 7);
    expect(tip).toBe(8);
  });

  test("computeContiguousTip after filling gap", async () => {
    // Fill gap 4-6
    for (const h of [4, 5, 6]) {
      await insertBlock(h);
    }
    const tip = await computeContiguousTip(db, 1);
    expect(tip).toBe(8);
  });
});

import { sql, type Kysely } from "kysely";
import type { Database } from "../types.ts";

export interface Gap {
  gapStart: number;
  gapEnd: number;
  size: number;
}

export async function findGaps(db: Kysely<Database>, limit?: number): Promise<Gap[]> {
  const limitClause = limit ? sql`LIMIT ${limit}` : sql``;
  const { rows } = await sql<{ gap_start: string; gap_end: string; size: string }>`
    SELECT gap_start, gap_end, gap_end - gap_start + 1 AS size
    FROM (
      SELECT height + 1 AS gap_start, next_height - 1 AS gap_end
      FROM (
        SELECT height, LEAD(height) OVER (ORDER BY height) AS next_height
        FROM blocks WHERE canonical = true
      ) sub
      WHERE next_height - height > 1
    ) gaps
    ORDER BY gap_start
    ${limitClause}
  `.execute(db);

  return rows.map((r) => ({
    gapStart: Number(r.gap_start),
    gapEnd: Number(r.gap_end),
    size: Number(r.size),
  }));
}

export async function countMissingBlocks(db: Kysely<Database>): Promise<number> {
  const { rows } = await sql<{ total: string }>`
    SELECT COALESCE(SUM(next_height - height - 1), 0) AS total
    FROM (
      SELECT height, LEAD(height) OVER (ORDER BY height) AS next_height
      FROM blocks WHERE canonical = true
    ) sub
    WHERE next_height - height > 1
  `.execute(db);

  return Number(rows[0]?.total ?? 0);
}

export async function computeContiguousTip(db: Kysely<Database>, fromHeight: number): Promise<number> {
  const { rows } = await sql<{ tip: string }>`
    SELECT COALESCE(MAX(height), ${fromHeight}) AS tip
    FROM (
      SELECT height, height - ROW_NUMBER() OVER (ORDER BY height) AS grp
      FROM blocks WHERE canonical = true AND height >= ${fromHeight}
    ) sub
    WHERE grp = (
      SELECT height - ROW_NUMBER() OVER (ORDER BY height)
      FROM blocks WHERE canonical = true AND height = ${fromHeight}
    )
  `.execute(db);

  return Number(rows[0]?.tip ?? fromHeight);
}

