  (globalThis as any).window = { StacksProvider: provider };
}

function clearProvider() {
  (globalThis as any).window = {};
}

beforeEach(() => {
  store.clear();
  (globalThis as any).localStorage = mockLocalStorage;
  clearProvider();
});

