import { describe, test, expect, beforeEach } from "bun:test";
import {
  getStorageData,
  setStorageData,
  clearStorage,
  cacheAddresses,
  type StorageData,
} from "../storage.ts";

// Mock localStorage
const store = new Map<string, string>();
