  #${MODAL_ID} .sl-wc-btn { display:block;width:100%;padding:12px;margin:8px 0;border:1px solid #e5e5e5;border-radius:12px;background:#fff;cursor:pointer;font-size:15px;font-weight:500;color:#1a1a1a;transition:background .15s }
  #${MODAL_ID} .sl-wc-btn:hover { background:#f5f5f5 }
  #${MODAL_ID} .sl-wc-divider { margin:16px 0;color:#999;font-size:13px }
  #${MODAL_ID} .sl-wc-qr { margin:16px auto 0 }
  #${MODAL_ID} .sl-wc-close { position:absolute;top:12px;right:16px;background:none;border:none;font-size:20px;cursor:pointer;color:#999 }
`;

export interface ModalOptions {
  wcUri?: string;
  onSelectInjected?: () => void;
  onClose?: () => void;
}

export function showModal(opts: ModalOptions): () => void {
  if (typeof document === "undefined") return () => {};

  // Remove existing
  document.getElementById(MODAL_ID)?.remove();

  const overlay = document.createElement("div");
  overlay.id = MODAL_ID;

  const style = document.createElement("style");
  style.textContent = STYLES;
  overlay.appendChild(style);

  const box = document.createElement("div");
  box.className = "sl-wc-box";
  box.style.position = "relative";

  // Close button
  const close = document.createElement("button");
  close.className = "sl-wc-close";
  close.textContent = "\u00d7";
  close.onclick = dismiss;
  box.appendChild(close);

  // Title
  const title = document.createElement("h2");
  title.className = "sl-wc-title";
  title.textContent = "Connect Wallet";
  box.appendChild(title);

  // Injected wallet button
  if (isWalletInstalled()) {
    const btn = document.createElement("button");
    btn.className = "sl-wc-btn";
    btn.textContent = "Browser Wallet";
    btn.onclick = () => {
      dismiss();
      opts.onSelectInjected?.();
    };
    box.appendChild(btn);
  }

  // QR code
  if (opts.wcUri) {
    if (isWalletInstalled()) {
      const divider = document.createElement("div");
      divider.className = "sl-wc-divider";
      divider.textContent = "or scan with mobile wallet";
      box.appendChild(divider);
    }

    const qr = document.createElement("div");
    qr.className = "sl-wc-qr";
    qr.innerHTML = qrSvg(opts.wcUri, { size: 240 });
    box.appendChild(qr);
  }

  overlay.appendChild(box);
  overlay.onclick = (e: any) => {
    if (e.target === overlay) dismiss();
  };

  document.body.appendChild(overlay);

  function dismiss() {
    overlay.remove();
    opts.onClose?.();
  }

  return dismiss;
}

export function hideModal() {
  if (typeof document === "undefined") return;
  document.getElementById(MODAL_ID)?.remove();
}

/** WalletProvider adapter for WalletConnect v2 */

import type { WalletProvider } from "../types.ts";
import type { WcProviderConfig, WcPairResult, WcSessionData } from "./types.ts";
import { WcSession } from "./session.ts";

export class WalletConnectProvider implements WalletProvider {
  private session: WcSession;

  constructor(config: WcProviderConfig) {
    this.session = new WcSession(config);
  }

  /** Try restoring a persisted session. Returns true if valid. */
  restore(): boolean {
    return this.session.restore();
  }

  /** Initiate pairing. Returns URI for QR + approval promise. */
  async pair(): Promise<WcPairResult> {
    return this.session.pair();
  }

  async request(method: string, params?: any): Promise<any> {
    return this.session.request(method, params);
  }

  disconnect(): void {
    this.session.disconnect();
  }

  get sessionData(): WcSessionData | null {
    return this.session.session;
  }
}

/**
 * Minimal QR code generator for WalletConnect URIs.
 * Produces SVG string. Byte-mode encoding, error correction level L.
 * Supports versions 1-10 (up to 271 bytes — plenty for WC URIs).
 */

// Version capacity table (byte mode, EC level L)
const CAPACITIES = [0, 17, 32, 53, 78, 106, 134, 154, 192, 230, 271];

// Generator polynomials for EC codewords per version (L level)
// [totalCodewords, ecCodewordsPerBlock, numBlocks]
const EC_PARAMS: [number, number, number][] = [
  [0, 0, 0], // v0 placeholder
  [26, 7, 1],
  [44, 10, 1],
  [70, 15, 1],
  [100, 20, 1],
  [134, 26, 1],
  [172, 18, 2],
  [196, 20, 2],
  [242, 24, 2],
  [292, 30, 2],
  [346, 18, 4],
];

function selectVersion(len: number): number {
  for (let v = 1; v <= 10; v++) {
    if (len <= CAPACITIES[v]) return v;
  }
  throw new Error("QR data too long");
}

// GF(256) arithmetic for Reed-Solomon
const GF_EXP = new Uint8Array(512);
const GF_LOG = new Uint8Array(256);
{
  let x = 1;
  for (let i = 0; i < 255; i++) {
    GF_EXP[i] = x;
    GF_LOG[x] = i;
    x = (x << 1) ^ (x >= 128 ? 0x11d : 0);
  }
  for (let i = 255; i < 512; i++) GF_EXP[i] = GF_EXP[i - 255];
}

function gfMul(a: number, b: number): number {
  if (a === 0 || b === 0) return 0;
  return GF_EXP[GF_LOG[a] + GF_LOG[b]];
}

function rsGenPoly(n: number): Uint8Array {
  let poly = new Uint8Array([1]);
  for (let i = 0; i < n; i++) {
    const next = new Uint8Array(poly.length + 1);
    for (let j = 0; j < poly.length; j++) {
      next[j] ^= poly[j];
      next[j + 1] ^= gfMul(poly[j], GF_EXP[i]);
    }
    poly = next;
  }
  return poly;
}

function rsEncode(data: Uint8Array, ecLen: number): Uint8Array {
  const gen = rsGenPoly(ecLen);
  const result = new Uint8Array(data.length + ecLen);
  result.set(data);
  for (let i = 0; i < data.length; i++) {
    const coef = result[i];
    if (coef === 0) continue;
    for (let j = 0; j < gen.length; j++) {
      result[i + j] ^= gfMul(gen[j], coef);
    }
  }
  return result.subarray(data.length);
}

function encodeData(bytes: Uint8Array, version: number): Uint8Array {
  const [totalCw, ecPerBlock, numBlocks] = EC_PARAMS[version];
  const dataCw = totalCw - ecPerBlock * numBlocks;

  // Build byte-mode bitstream
  const bits: number[] = [];
  const push = (val: number, len: number) => {
    for (let i = len - 1; i >= 0; i--) bits.push((val >> i) & 1);
  };

  push(0b0100, 4); // byte mode indicator
  push(bytes.length, version <= 9 ? 8 : 16); // character count
  for (const b of bytes) push(b, 8);
  push(0, 4); // terminator (up to 4 bits)

  // Pad to byte boundary
  while (bits.length % 8 !== 0) bits.push(0);

  // Build codeword array
  const codewords = new Uint8Array(dataCw);
  for (let i = 0; i < dataCw; i++) {
    let byte = 0;
    for (let j = 0; j < 8; j++) {
      const idx = i * 8 + j;
      byte = (byte << 1) | (idx < bits.length ? bits[idx] : 0);
    }
    codewords[i] = byte;
  }

  // Pad codewords
  let padByte = 0xec;
  for (let i = Math.ceil(bits.length / 8); i < dataCw; i++) {
    codewords[i] = padByte;
    padByte = padByte === 0xec ? 0x11 : 0xec;
  }

  // Reed-Solomon EC
  const cwPerBlock = Math.floor(dataCw / numBlocks);
  const dataBlocks: Uint8Array[] = [];
  const ecBlocks: Uint8Array[] = [];
  let offset = 0;
  for (let b = 0; b < numBlocks; b++) {
    const blockLen = cwPerBlock + (b < dataCw % numBlocks ? 1 : 0);
    const block = codewords.subarray(offset, offset + blockLen);
    dataBlocks.push(block);
    ecBlocks.push(rsEncode(block, ecPerBlock));
    offset += blockLen;
  }

  // Interleave
  const result: number[] = [];
  const maxDataLen = Math.max(...dataBlocks.map((b) => b.length));
  for (let i = 0; i < maxDataLen; i++) {
    for (const block of dataBlocks) {
      if (i < block.length) result.push(block[i]);
    }
  }
  for (let i = 0; i < ecPerBlock; i++) {
    for (const block of ecBlocks) {
      if (i < block.length) result.push(block[i]);
    }
  }

  return new Uint8Array(result);
}

// QR matrix operations

type Matrix = Uint8Array[];

function createMatrix(size: number): Matrix {
  return Array.from({ length: size }, () => new Uint8Array(size));
}

function setModule(m: Matrix, r: number, c: number, val: number, reserved: Matrix) {
  if (r >= 0 && r < m.length && c >= 0 && c < m.length) {
    m[r][c] = val;
    reserved[r][c] = 1;
  }
}

function addFinderPattern(m: Matrix, r: number, c: number, res: Matrix) {
  for (let dr = -1; dr <= 7; dr++) {
    for (let dc = -1; dc <= 7; dc++) {
      const rr = r + dr, cc = c + dc;
      if (rr < 0 || rr >= m.length || cc < 0 || cc >= m.length) continue;
      const inOuter = dr >= 0 && dr <= 6 && dc >= 0 && dc <= 6;
      const inInner = dr >= 2 && dr <= 4 && dc >= 2 && dc <= 4;
      const onBorder = dr === 0 || dr === 6 || dc === 0 || dc === 6;
      const val = inInner || (inOuter && onBorder) ? 1 : 0;
      setModule(m, rr, cc, val, res);
    }
  }
}

function addTimingPatterns(m: Matrix, res: Matrix) {
  for (let i = 8; i < m.length - 8; i++) {
    const val = i % 2 === 0 ? 1 : 0;
    if (!res[6][i]) setModule(m, 6, i, val, res);
    if (!res[i][6]) setModule(m, i, 6, val, res);
  }
}

function addFormatInfo(m: Matrix, res: Matrix) {
  // EC level L (01), mask 0 (000) → format bits 01000 → with BCH: 0x77C0 ... simplified
  // Use pre-computed format info for L/mask0: 111011111000100
  const fmt = 0b111011111000100;
  const n = m.length;
  for (let i = 0; i < 15; i++) {
    const bit = (fmt >> (14 - i)) & 1;
    // Around top-left finder
    if (i < 6) setModule(m, 8, i, bit, res);
    else if (i === 6) setModule(m, 8, 7, bit, res);
    else if (i === 7) setModule(m, 8, 8, bit, res);
    else if (i === 8) setModule(m, 7, 8, bit, res);
    else setModule(m, 14 - i, 8, bit, res);

    // Around other finders
    if (i < 8) setModule(m, n - 1 - i, 8, bit, res);
    else setModule(m, 8, n - 15 + i, bit, res);
  }
  // Dark module
  setModule(m, n - 8, 8, 1, res);
}

function placeData(m: Matrix, res: Matrix, data: Uint8Array) {
  const n = m.length;
  let bitIdx = 0;
  const totalBits = data.length * 8;

  let col = n - 1;
  let upward = true;

  while (col >= 0) {
    if (col === 6) col--; // skip timing column
    const rows = upward
      ? Array.from({ length: n }, (_, i) => n - 1 - i)
      : Array.from({ length: n }, (_, i) => i);

    for (const row of rows) {
      for (const dc of [0, -1]) {
        const c = col + dc;
        if (c < 0 || res[row][c]) continue;
        if (bitIdx < totalBits) {
          const byteIdx = bitIdx >> 3;
          const bitPos = 7 - (bitIdx & 7);
          const bit = (data[byteIdx] >> bitPos) & 1;
          // Apply mask 0: (row + col) % 2 === 0
          m[row][c] = bit ^ ((row + c) % 2 === 0 ? 1 : 0);
          bitIdx++;
        }
      }
    }

    col -= 2;
    upward = !upward;
  }
}

function buildMatrix(version: number, codewords: Uint8Array): Matrix {
  const n = version * 4 + 17;
  const m = createMatrix(n);
  const res = createMatrix(n); // reserved modules

  // Finder patterns
  addFinderPattern(m, 0, 0, res);
  addFinderPattern(m, 0, n - 7, res);
  addFinderPattern(m, n - 7, 0, res);

  addTimingPatterns(m, res);
  addFormatInfo(m, res);

  // Alignment patterns for v >= 2
  if (version >= 2) {
    const pos = [6, version * 4 + 10]; // simplified for v2-v6
    for (const r of pos) {
      for (const c of pos) {
        // Skip if overlapping finder
        if (res[r]?.[c]) continue;
        for (let dr = -2; dr <= 2; dr++) {
          for (let dc = -2; dc <= 2; dc++) {
            const val =
              Math.abs(dr) === 2 || Math.abs(dc) === 2 || (dr === 0 && dc === 0) ? 1 : 0;
            setModule(m, r + dr, c + dc, val, res);
          }
        }
      }
    }
  }

  placeData(m, res, codewords);
  return m;
}

/** Generate a QR code as an SVG string for the given data. */
export function qrSvg(data: string, opts?: { size?: number; dark?: string; light?: string }): string {
  const size = opts?.size ?? 256;
  const dark = opts?.dark ?? "#000000";
  const light = opts?.light ?? "#ffffff";

  const bytes = new TextEncoder().encode(data);
  const version = selectVersion(bytes.length);
  const codewords = encodeData(bytes, version);
  const matrix = buildMatrix(version, codewords);

  const n = matrix.length;
  const quiet = 4; // quiet zone modules
  const total = n + quiet * 2;
  const scale = size / total;

  let paths = "";
  for (let r = 0; r < n; r++) {
    for (let c = 0; c < n; c++) {
      if (matrix[r][c]) {
        const x = (c + quiet) * scale;
        const y = (r + quiet) * scale;
        paths += `M${x},${y}h${scale}v${scale}h-${scale}z`;
      }
    }
  }

  return [
    `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${size} ${size}" width="${size}" height="${size}">`,
    `<rect width="${size}" height="${size}" fill="${light}"/>`,
    `<path d="${paths}" fill="${dark}"/>`,
    `</svg>`,
  ].join("");
}

/** WalletConnect v2 relay client (wss://relay.walletconnect.com) */

import type { WcRelayMessage } from "./types.ts";
import {
  encryptType0,
  decryptType0,
  encodeBase64,
  decodeBase64,
  createRelayAuthJwt,
} from "./crypto.ts";

const DEFAULT_RELAY = "wss://relay.walletconnect.com";
const DEFAULT_TTL = 300; // 5 minutes

type PendingRpc = {
  resolve: (v: unknown) => void;
  reject: (e: Error) => void;
};

type SubscriptionHandler = (message: WcRelayMessage) => void;

export class WcRelay {
  private ws: WebSocket | null = null;
  private url: string;
  private projectId: string;
  private nextId = Date.now() * 1000 + Math.floor(Math.random() * 1000);
  private pending = new Map<number, PendingRpc>();
  private subscriptions = new Map<string, SubscriptionHandler>();
  /** Map subscription ID (from server) → topic */
  private subIdToTopic = new Map<string, string>();
  private destroyed = false;
  private reconnecting = false;
  private reconnectAttempt = 0;
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private connectPromise: Promise<void> | null = null;
  private connectReject: ((e: Error) => void) | null = null;

  constructor(projectId: string, relayUrl?: string) {
    this.projectId = projectId;
    this.url = relayUrl ?? DEFAULT_RELAY;
  }

  // -- Connection --

  async connect(): Promise<void> {
    if (this.ws?.readyState === WebSocket.OPEN) return;
    if (this.connectPromise) return this.connectPromise;

    this.connectPromise = new Promise<void>((resolve, reject) => {
      this.connectReject = reject;
      const { jwt } = createRelayAuthJwt(this.url);
      const wsUrl = `${this.url}/?auth=${jwt}&projectId=${this.projectId}`;
      this.ws = new WebSocket(wsUrl);

      this.ws.addEventListener(
        "open",
        () => {
          this.reconnectAttempt = 0;
          this.reconnecting = false;
          this.connectPromise = null;
          this.connectReject = null;
          resolve();
        },
        { once: true },
      );

      this.ws.addEventListener(
        "error",
        (e) => {
          this.connectPromise = null;
          this.connectReject = null;
          reject(new Error(`WC relay connection failed: ${e}`));
        },
        { once: true },
      );

      this.ws.addEventListener("message", (event) => {
        this.handleMessage(
          typeof event.data === "string"
            ? event.data
            : new TextDecoder().decode(event.data as ArrayBuffer),
        );
      });

      this.ws.addEventListener("close", () => {
        this.connectPromise = null;
        if (!this.destroyed) this.handleDisconnect();
      });
    });

    return this.connectPromise;
  }

  // -- Publish/Subscribe --

  async subscribe(
    topic: string,
    handler: SubscriptionHandler,
  ): Promise<string> {
    await this.connect();
    this.subscriptions.set(topic, handler);
    const subId = (await this.rpc("irn_subscribe", { topic })) as string;
    this.subIdToTopic.set(subId, topic);
    return subId;
  }

  async publish(
    topic: string,
    message: string,
    tag: number,
    ttl = DEFAULT_TTL,
  ): Promise<void> {
    await this.connect();
    await this.rpc("irn_publish", {
      topic,
      message,
      ttl,
      tag,
      prompt: false,
    });
  }

  /** Encrypt + publish a type-0 envelope */
  async publishEncrypted(
    topic: string,
    symKey: Uint8Array,
    payload: unknown,
    tag: number,
    ttl = DEFAULT_TTL,
  ): Promise<void> {
    const plaintext = JSON.stringify(payload);
    const envelope = encryptType0(symKey, plaintext);
    await this.publish(topic, encodeBase64(envelope), tag, ttl);
  }

  // -- Internal --

  private rpc(method: string, params: Record<string, unknown>): Promise<unknown> {
    return new Promise((resolve, reject) => {
      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
        return reject(new Error("WC relay not connected"));
      }
      const id = this.nextId++;
      this.pending.set(id, { resolve, reject });
      this.ws.send(JSON.stringify({ id, jsonrpc: "2.0", method, params }));
    });
  }

  private handleMessage(raw: string) {
    let msg: any;
    try {
      msg = JSON.parse(raw);
    } catch {
      return;
    }

    // RPC response
    if ("id" in msg && msg.id != null && this.pending.has(msg.id)) {
      const p = this.pending.get(msg.id)!;
      this.pending.delete(msg.id);
      if (msg.error) {
        p.reject(new Error(`WC relay error: ${msg.error.message}`));
      } else {
        p.resolve(msg.result);
      }
      return;
    }

    // Server push (irn_subscription)
    if (msg.method === "irn_subscription" && msg.params) {
      const { id: subId, data } = msg.params;
      const topic = data?.topic ?? this.subIdToTopic.get(subId);
      const handler = topic ? this.subscriptions.get(topic) : undefined;
      if (handler && data) {
        handler({
          topic: data.topic,
          message: data.message,
          publishedAt: data.publishedAt ?? Date.now(),
          tag: data.tag ?? 0,
        });
      }
      // Acknowledge
      if (msg.id != null) {
        this.ws?.send(
          JSON.stringify({ id: msg.id, jsonrpc: "2.0", result: true }),
        );
      }
    }
  }

  private handleDisconnect() {
    this.ws = null;
    for (const [, p] of this.pending) {
      p.reject(new Error("WC relay disconnected"));
    }
    this.pending.clear();

    if (this.subscriptions.size > 0 && this.reconnectAttempt < 5) {
      this.scheduleReconnect();
    }
  }

  private scheduleReconnect() {
    if (this.destroyed || this.reconnecting) return;
    this.reconnecting = true;
    const delay = 1000 * 2 ** this.reconnectAttempt;
    this.reconnectAttempt++;

    this.reconnectTimer = setTimeout(async () => {
      this.reconnecting = false;
      try {
        await this.connect();
        // Re-subscribe all topics
        for (const [topic] of this.subscriptions) {
          const subId = (await this.rpc("irn_subscribe", { topic })) as string;
          this.subIdToTopic.set(subId, topic);
        }
      } catch {
        if (!this.destroyed && this.subscriptions.size > 0) {
          this.handleDisconnect();
        }
      }
    }, delay);
  }

  destroy() {
    this.destroyed = true;
    if (this.reconnectTimer) clearTimeout(this.reconnectTimer);
    if (this.connectReject) {
      this.connectReject(new Error("WC relay destroyed"));
      this.connectReject = null;
      this.connectPromise = null;
    }
    for (const [, p] of this.pending) {
      p.reject(new Error("WC relay destroyed"));
    }
    this.pending.clear();
    this.subscriptions.clear();
    this.subIdToTopic.clear();
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
  }
}

/** WalletConnect v2 session state machine (pairing → proposal → settlement) */

import type {
  WcProviderConfig,
  WcPairResult,
  WcSessionSettled,
  WcSessionData,
  WcJsonRpc,
  WcProposal,
} from "./types.ts";
import {
  generateKeyPair,
  generateSymKey,
  deriveSymKey,
  symKeyToTopic,
  decryptType0,
  decryptType1,
  decodeBase64,
  bytesToHex,
  hexToBytes,
} from "./crypto.ts";
import { WcRelay } from "./relay.ts";

const STORAGE_KEY = "@secondlayer/wc:session";
const SESSION_EXPIRY = 7 * 24 * 60 * 60; // 7 days in seconds

const STACKS_METHODS = [
  "stx_getAddresses",
  "stx_transferStx",
  "stx_callContract",
  "stx_deployContract",
  "stx_signMessage",
  "stx_signTransaction",
];

const STACKS_EVENTS = ["chainChanged", "accountsChanged"];

declare const localStorage:
  | {
      getItem(key: string): string | null;
      setItem(key: string, value: string): void;
      removeItem(key: string): void;
    }
  | undefined;

function getStorage() {
  return typeof localStorage !== "undefined" ? localStorage : undefined;
}

export class WcSession {
  private relay: WcRelay;
  private config: WcProviderConfig;
  private chains: string[];

  // Pairing state
  private pairingSymKey: Uint8Array | null = null;
  private pairingTopic: string | null = null;
  private selfKeyPair: { privateKey: Uint8Array; publicKey: Uint8Array } | null = null;

  // Session state
  private sessionData: WcSessionData | null = null;
  private sessionSymKey: Uint8Array | null = null;
  private pending = new Map<
    number,
    { resolve: (v: unknown) => void; reject: (e: Error) => void }
  >();
  private nextId = Date.now();

  constructor(config: WcProviderConfig) {
    this.config = config;
    this.chains = config.chains ?? ["stacks:1"];
    this.relay = new WcRelay(config.projectId, config.relayUrl);
  }

  /** Try restoring a persisted session. Returns true if valid session found. */
  restore(): boolean {
    try {
      const raw = getStorage()?.getItem(STORAGE_KEY);
      if (!raw) return false;
      const data = JSON.parse(raw) as WcSessionData;
      if (data.expiry < Date.now() / 1000) {
        getStorage()?.removeItem(STORAGE_KEY);
        return false;
      }
      this.sessionData = data;
      this.sessionSymKey = hexToBytes(data.symKey);
      // Subscribe to session topic for incoming requests (fire-and-forget)
      this.subscribeSession().catch(() => {});
      return true;
    } catch {
      return false;
    }
  }

  /** Initiate pairing. Returns URI for QR code + approval promise. */
  async pair(): Promise<WcPairResult> {
    this.pairingSymKey = generateSymKey();
    this.pairingTopic = symKeyToTopic(this.pairingSymKey);
    this.selfKeyPair = generateKeyPair();

    const symKeyHex = bytesToHex(this.pairingSymKey);
    const uri = `wc:${this.pairingTopic}@2?relay-protocol=irn&symKey=${symKeyHex}`;

    const approval = new Promise<WcSessionSettled>((resolve, reject) => {
      this.relay
        .subscribe(this.pairingTopic!, (msg) => {
          try {
            this.handlePairingMessage(msg.message, resolve, reject);
          } catch (err) {
            reject(err instanceof Error ? err : new Error(String(err)));
          }
        })
        .catch(reject);
    });

    return { uri, approval };
  }

  /** Send a JSON-RPC request over the session. */
  async request(method: string, params?: unknown): Promise<unknown> {
    if (!this.sessionData || !this.sessionSymKey) {
      throw new Error("No active WC session");
    }

    const id = this.nextId++;
    const payload = {
      id,
      jsonrpc: "2.0" as const,
      method: "wc_sessionRequest",
      params: {
        request: { method, params },
        chainId: this.chains[0],
      },
    };

    return new Promise((resolve, reject) => {
      this.pending.set(id, { resolve, reject });
      this.relay
        .publishEncrypted(
          this.sessionData!.topic,
          this.sessionSymKey!,
          payload,
          1108, // tag for session request
          SESSION_EXPIRY,
        )
        .catch((err) => {
          this.pending.delete(id);
          reject(err);
        });
    });
  }

  disconnect() {
    if (this.sessionData && this.sessionSymKey) {
      const id = this.nextId++;
      const payload = {
        id,
        jsonrpc: "2.0",
        method: "wc_sessionDelete",
        params: { code: 6000, message: "User disconnected" },
      };
      // Best-effort notify peer
      this.relay
        .publishEncrypted(
          this.sessionData.topic,
          this.sessionSymKey,
          payload,
          1112,
        )
        .catch(() => {});
    }
    this.sessionData = null;
    this.sessionSymKey = null;
    this.pending.clear();
    getStorage()?.removeItem(STORAGE_KEY);
    this.relay.destroy();
  }

  get session(): WcSessionData | null {
    return this.sessionData;
  }

  // -- Internal --

  private handlePairingMessage(
    message: string,
    resolve: (v: WcSessionSettled) => void,
    reject: (e: Error) => void,
  ) {
    const envelope = decodeBase64(message);
    let plaintext: string;

    // Could be type 0 (symmetric) or type 1 (asymmetric)
    if (envelope[0] === 0x01 && this.selfKeyPair) {
      plaintext = decryptType1(this.selfKeyPair.privateKey, envelope);
    } else if (this.pairingSymKey) {
      plaintext = decryptType0(this.pairingSymKey, envelope);
    } else {
      return;
    }

    let rpc: WcJsonRpc;
    try {
      rpc = JSON.parse(plaintext) as WcJsonRpc;
    } catch {
      return;
    }

    if (rpc.method === "wc_sessionPropose") {
      this.handleProposal(rpc as WcJsonRpc<WcProposal>, resolve, reject).catch(reject);
    }
  }

  private async handleProposal(
    rpc: WcJsonRpc<WcProposal>,
    resolve: (v: WcSessionSettled) => void,
    reject: (e: Error) => void,
  ) {
    try {
      const proposal = rpc.params;
      const peerPublicKey = hexToBytes(proposal.proposer.publicKey);

      // Generate session key pair + derive session symmetric key
      const sessionKp = generateKeyPair();
      const sessionSymKey = deriveSymKey(sessionKp.privateKey, peerPublicKey);
      const sessionTopic = symKeyToTopic(sessionSymKey);

      const expiry = Math.floor(Date.now() / 1000) + SESSION_EXPIRY;

      const settled: WcSessionSettled = {
        relay: { protocol: "irn" },
        namespaces: {
          stacks: {
            chains: this.chains,
            methods: STACKS_METHODS,
            events: STACKS_EVENTS,
            accounts: this.chains.map((c) => `${c}:placeholder`),
          },
        },
        controller: {
          publicKey: bytesToHex(sessionKp.publicKey),
          metadata: this.config.metadata,
        },
        expiry,
      };

      // Approve the proposal on the pairing topic
      const approvePayload = {
        id: rpc.id,
        jsonrpc: "2.0",
        result: {
          relay: { protocol: "irn" },
          responderPublicKey: bytesToHex(sessionKp.publicKey),
        },
      };

      await this.relay.publishEncrypted(
        this.pairingTopic!,
        this.pairingSymKey!,
        approvePayload,
        1101, // tag for session propose response
      );

      // Subscribe to session topic
      this.sessionSymKey = sessionSymKey;
      this.sessionData = {
        topic: sessionTopic,
        symKey: bytesToHex(sessionSymKey),
        peerMeta: proposal.proposer.metadata,
        expiry,
        accounts: [],
        controllerPublicKey: proposal.proposer.publicKey,
      };

      await this.subscribeSession();

      // Send session settle on the new session topic
      const settlePayload = {
        id: this.nextId++,
        jsonrpc: "2.0",
        method: "wc_sessionSettle",
        params: settled,
      };

      await this.relay.publishEncrypted(
        sessionTopic,
        sessionSymKey,
        settlePayload,
        1104, // tag for session settle
      );

      // Persist
      getStorage()?.setItem(STORAGE_KEY, JSON.stringify(this.sessionData));

      resolve(settled);
    } catch (err) {
      reject(err instanceof Error ? err : new Error(String(err)));
    }
  }

  private async subscribeSession() {
    if (!this.sessionData || !this.sessionSymKey) return;

    const symKey = this.sessionSymKey;
    await this.relay.subscribe(this.sessionData.topic, (msg) => {
      try {
        const envelope = decodeBase64(msg.message);
        const plaintext = decryptType0(symKey, envelope);
        const rpc = JSON.parse(plaintext);

        // Response to our request
        if ("id" in rpc && this.pending.has(rpc.id)) {
          const p = this.pending.get(rpc.id)!;
          this.pending.delete(rpc.id);
          if (rpc.error) {
            p.reject(new Error(rpc.error.message ?? "WC request failed"));
          } else {
            p.resolve(rpc.result);
          }
        }

        // Session delete from peer
        if (rpc.method === "wc_sessionDelete") {
          this.sessionData = null;
          this.sessionSymKey = null;
          this.pending.clear();
          getStorage()?.removeItem(STORAGE_KEY);
        }
      } catch {
        // ignore malformed messages
      }
    });
  }
}

/** WalletConnect v2 protocol types */

export interface WcMetadata {
  name: string;
  description: string;
  url: string;
  icons: string[];
}

export interface WcNamespace {
  chains: string[];
  methods: string[];
  events: string[];
}

export interface WcProposal {
  id: number;
  proposer: {
    publicKey: string;
    metadata: WcMetadata;
  };
  requiredNamespaces: Record<string, WcNamespace>;
}

export interface WcSessionSettled {
  relay: { protocol: string };
  namespaces: Record<string, WcNamespace & { accounts: string[] }>;
  controller: { publicKey: string; metadata: WcMetadata };
  expiry: number;
}

export interface WcJsonRpc<T = unknown> {
  id: number;
  jsonrpc: "2.0";
  method: string;
  params: T;
}

export interface WcJsonRpcResult<T = unknown> {
  id: number;
  jsonrpc: "2.0";
  result: T;
}

export interface WcJsonRpcError {
  id: number;
  jsonrpc: "2.0";
  error: { code: number; message: string; data?: unknown };
}

/** Type 0 = symmetric key (pairing), Type 1 = asymmetric (session proposal) */
export type WcEnvelopeType = 0 | 1;

export interface WcRelayMessage {
  topic: string;
  message: string;
  publishedAt: number;
  tag: number;
}

export interface WcPairResult {
  uri: string;
  approval: Promise<WcSessionSettled>;
}

export interface WcProviderConfig {
  projectId: string;
  metadata: WcMetadata;
  relayUrl?: string;
  /** CAIP-2 chain IDs. Default: ["stacks:1"] */
  chains?: string[];
}

/** Persisted session data */
export interface WcSessionData {
  topic: string;
  symKey: string;
  peerMeta: WcMetadata;
  expiry: number;
  accounts: string[];
  controllerPublicKey: string;
}

