import {
  getPublicKey as nobleGetPublicKey,
  sign,
  etc,
} from "@noble/secp256k1";
import { hmac } from "@noble/hashes/hmac.js";
import { sha256 } from "@noble/hashes/sha2.js";
import {
  bytesToHex,
  hexToBytes,
  intToBytes,
  intToHex,
  concatBytes,
} from "../utils/encoding.ts";
import { hashP2PKH, txidFromBytes } from "../utils/hash.ts";
import {
  AuthType,
  AddressHashMode,
  PubKeyEncoding,
  RECOVERABLE_ECDSA_SIG_LENGTH_BYTES,
  type SingleSigSpendingCondition,
  type SpendingCondition,
  type Authorization,
  type StandardAuthorization,
  type SponsoredAuthorization,
} from "./types.ts";

// Ensure sync signing is available
etc.hmacSha256Sync = (key: Uint8Array, ...msgs: Uint8Array[]) => {
  const h = hmac.create(sha256, key);
  msgs.forEach((msg) => h.update(msg));
  return h.digest();
};

const EMPTY_SIG = bytesToHex(new Uint8Array(RECOVERABLE_ECDSA_SIG_LENGTH_BYTES));

export function createSingleSigSpendingCondition(
  publicKey: string,
  nonce: bigint,
  fee: bigint
): SingleSigSpendingCondition {
  const pubKeyBytes = hexToBytes(publicKey);
  const signer = hashP2PKH(pubKeyBytes);
  const isCompressed = pubKeyBytes.length === 33;

  return {
    hashMode: AddressHashMode.P2PKH,
    signer,
    nonce,
    fee,
    keyEncoding: isCompressed ? PubKeyEncoding.Compressed : PubKeyEncoding.Uncompressed,
    signature: EMPTY_SIG,
  };
}

export function createStandardAuth(
  spendingCondition: SpendingCondition
): StandardAuthorization {
  return { authType: AuthType.Standard, spendingCondition };
}

export function createSponsoredAuth(
  spendingCondition: SpendingCondition,
  sponsorSpendingCondition?: SpendingCondition
): SponsoredAuthorization {
  return {
    authType: AuthType.Sponsored,
    spendingCondition,
    sponsorSpendingCondition: sponsorSpendingCondition ?? createSingleSigSpendingCondition(
      "0".repeat(66),
      0n,
      0n
    ),
  };
}

function clearCondition(condition: SpendingCondition): SpendingCondition {
  if ("signature" in condition) {
    return {
      ...condition,
      nonce: 0n,
      fee: 0n,
      signature: EMPTY_SIG,
    };
  }
  return {
    ...condition,
    nonce: 0n,
    fee: 0n,
    fields: [],
  };
}

export function intoInitialSighashAuth(auth: Authorization): Authorization {
  if (auth.authType === AuthType.Standard) {
    return createStandardAuth(clearCondition(auth.spendingCondition));
  }
  return createSponsoredAuth(
    clearCondition(auth.spendingCondition),
    clearCondition(createSingleSigSpendingCondition("0".repeat(66), 0n, 0n))
  );
}

/** Compute pre-sign sighash = sha512/256(prevSigHash + authType + fee + nonce) */
export function sigHashPreSign(
  curSigHash: string,
  authType: number,
  fee: bigint,
  nonce: bigint
): string {
  const data = concatBytes(
    hexToBytes(curSigHash),
    new Uint8Array([authType]),
    intToBytes(fee, 8),
    intToBytes(nonce, 8)
  );
  return txidFromBytes(data);
}

/** Compute post-sign sighash = sha512/256(preSigHash + pubKeyEncoding + signature) */
export function sigHashPostSign(
  curSigHash: string,
  pubKeyEncoding: number,
  signature: string
): string {
  const data = concatBytes(
    hexToBytes(curSigHash),
    new Uint8Array([pubKeyEncoding]),
    hexToBytes(signature)
  );
  return txidFromBytes(data);
}

/** Sign with private key and return VRS signature (recoveryId + r + s) */
function signWithKey(privateKey: string, messageHash: string): string {
  const keyBytes = hexToBytes(privateKey).slice(0, 32);
  const sig = sign(messageHash, keyBytes, { lowS: true });
  const recoveryIdHex = intToHex(sig.recovery, 1);
  return recoveryIdHex + sig.toCompactHex();
}

export function nextSignature(
  curSigHash: string,
  authType: number,
  fee: bigint,
  nonce: bigint,
  privateKey: string
): { nextSig: string; nextSigHash: string } {
  const sigHashPre = sigHashPreSign(curSigHash, authType, fee, nonce);

  const keyBytes = hexToBytes(privateKey).slice(0, 32);
  const pubKey = nobleGetPublicKey(keyBytes, true);
  const isCompressed = pubKey.length === 33;
  const pubKeyEncoding = isCompressed
    ? PubKeyEncoding.Compressed
    : PubKeyEncoding.Uncompressed;

  const nextSig = signWithKey(privateKey, sigHashPre);
  const nextSigHash = sigHashPostSign(sigHashPre, pubKeyEncoding, nextSig);

  return { nextSig, nextSigHash };
}

# Transactions

Build, sign, and serialize Stacks transactions (SIP-005).

## Token Transfer

```typescript
import { buildTokenTransfer, signTransaction, serializeTransactionHex } from "@secondlayer/stacks/transactions";

const tx = buildTokenTransfer({
  recipient: "SP2J6ZY48GV1EZ5V2V5RB9MP66SW86PYKKNRV9EJ7",
  amount: 1_000_000n,
  memo: "coffee",
  fee: 200n,
  nonce: 0n,
  publicKey: "03ab...",
});

const signed = signTransaction(tx, "0xprivatekey...");
const hex = serializeTransactionHex(signed);
// broadcast hex to the network
```

## Contract Call

```typescript
import { buildContractCall, signTransaction } from "@secondlayer/stacks/transactions";
import { Cl } from "@secondlayer/stacks/clarity";

const tx = buildContractCall({
  contractAddress: "SP2J6ZY48GV1EZ5V2V5RB9MP66SW86PYKKNRV9EJ7",
  contractName: "my-contract",
  functionName: "transfer",
  functionArgs: [Cl.uint(100), Cl.principal("SP3FBR2AGK5H9QBDH3EEN6DF8EK8JY7RX8QJ5SVTE")],
  fee: 500n,
  nonce: 1n,
  publicKey: "03ab...",
});
```

## Contract Deploy

```typescript
import { buildContractDeploy, signTransaction } from "@secondlayer/stacks/transactions";

const tx = buildContractDeploy({
  contractName: "my-token",
  codeBody: "(define-fungible-token my-token)",
  fee: 10_000n,
  nonce: 2n,
  publicKey: "03ab...",
});
```

## Multi-Sig (2-of-3)

```typescript
import { buildTokenTransfer, signMultiSig } from "@secondlayer/stacks/transactions";

const tx = buildTokenTransfer({
  recipient: "SP2J6ZY48GV1EZ5V2V5RB9MP66SW86PYKKNRV9EJ7",
  amount: 1_000_000n,
  fee: 200n,
  nonce: 0n,
  publicKeys: [pk1, pk2, pk3],
  signaturesRequired: 2,
});

// Sign sequentially — auto-finalizes when threshold is met
const partial = signMultiSig(tx, key1, [pk1, pk2, pk3]);
const full = signMultiSig(partial, key2, [pk1, pk2, pk3]);
```

### Non-Sequential (SIP-027)

Signers can sign independently and combine later.

```typescript
import { buildTokenTransfer, signMultiSig, combineMultiSigSignatures } from "@secondlayer/stacks/transactions";
import { AddressHashMode } from "@secondlayer/stacks/transactions";

const tx = buildTokenTransfer({
  recipient: "SP2J6ZY48GV1EZ5V2V5RB9MP66SW86PYKKNRV9EJ7",
  amount: 1_000_000n,
  fee: 200n,
  nonce: 0n,
  publicKeys: [pk1, pk2, pk3],
  signaturesRequired: 2,
  hashMode: AddressHashMode.P2SH_NonSequential,
});

const sig1 = signMultiSig(tx, key1, [pk1, pk2, pk3]);
const sig3 = signMultiSig(tx, key3, [pk1, pk2, pk3]);
const combined = combineMultiSigSignatures(tx, [sig1, sig3]);
```

## Sponsored Transactions

```typescript
import { buildTokenTransfer, signTransaction, signSponsor } from "@secondlayer/stacks/transactions";

// Origin builds with sponsored: true and fee: 0
const tx = buildTokenTransfer({
  recipient: "SP2J6ZY48GV1EZ5V2V5RB9MP66SW86PYKKNRV9EJ7",
  amount: 1_000_000n,
  fee: 0n,
  nonce: 0n,
  publicKey: originPubKey,
  sponsored: true,
});

// Origin signs
const originSigned = signTransaction(tx, originKey);

// Sponsor sets fee and signs
const fullySigned = signSponsor(originSigned, sponsorKey);
```

## Wire Format

```typescript
