# Transports

Transport layer for communicating with Stacks nodes.

## HTTP (Default)

```typescript
import { http } from "@secondlayer/stacks";

// Uses chain's default RPC URL
const transport = http();

// Custom URL
const transport = http({ url: "https://my-node.example.com" });

// With options
const transport = http({
  url: "https://my-node.example.com",
  apiKey: "my-api-key",
  timeout: 30_000,
  retryCount: 3,
  retryDelay: 1_000,
});
```

## WebSocket

```typescript
import { webSocket } from "@secondlayer/stacks";

const transport = webSocket();

// Custom URL
const transport = webSocket({ url: "wss://my-node.example.com" });
```

## Fallback

Tries transports in order, falls back on failure.

```typescript
import { fallback, http } from "@secondlayer/stacks";

const transport = fallback([
  http({ url: "https://primary-node.com" }),
  http({ url: "https://backup-node.com" }),
]);
```

## Custom

```typescript
import { custom } from "@secondlayer/stacks";

const transport = custom({
  async request(path, options) {
    const response = await fetch(`https://my-api.com${path}`, {
      method: options?.method ?? "GET",
      body: options?.body ? JSON.stringify(options.body) : undefined,
    });
    return response.json();
  },
});
```

